-- ============================================================
-- PART 4: Canonical client and recipe operations data
-- ============================================================
-- Run order:
--   1. seed-part1-base.sql
--   2. seed-part2-users.sql
--   3. seed-part3-recipes.sql
--   4. this file
--
-- Purpose:
--   - seed canonical client restrictions
--   - seed pantry and goal preferences for realistic kitchen tests
--   - seed dietitian-client binding and access keys
-- ============================================================

BEGIN;

-- Refresh deterministic clinical link records.
DELETE FROM "DietitianClientLinks"
WHERE "ClientId" IN (
    'cc000001-0000-0000-0000-000000000000'::uuid,
    'cc000002-0000-0000-0000-000000000000'::uuid,
    'cc000003-0000-0000-0000-000000000000'::uuid,
    'cc000004-0000-0000-0000-000000000000'::uuid,
    'cc000005-0000-0000-0000-000000000000'::uuid,
    'cc000006-0000-0000-0000-000000000000'::uuid,
    'cc000007-0000-0000-0000-000000000000'::uuid,
    'cc000008-0000-0000-0000-000000000000'::uuid,
    'cc000009-0000-0000-0000-000000000000'::uuid,
    'cc00000a-0000-0000-0000-000000000000'::uuid
);


DELETE FROM "AccessKeys"
WHERE "ClientId" IN (
    'cc000001-0000-0000-0000-000000000000'::uuid,
    'cc000002-0000-0000-0000-000000000000'::uuid,
    'cc000003-0000-0000-0000-000000000000'::uuid,
    'cc000004-0000-0000-0000-000000000000'::uuid,
    'cc000005-0000-0000-0000-000000000000'::uuid,
    'cc000006-0000-0000-0000-000000000000'::uuid,
    'cc000007-0000-0000-0000-000000000000'::uuid,
    'cc000008-0000-0000-0000-000000000000'::uuid,
    'cc000009-0000-0000-0000-000000000000'::uuid,
    'cc00000a-0000-0000-0000-000000000000'::uuid
);


ON CONFLICT ("ClientId") DO UPDATE
SET
    "PrimaryGoal" = EXCLUDED."PrimaryGoal",
    "DietStyle" = EXCLUDED."DietStyle",
    "CookingTimePreference" = EXCLUDED."CookingTimePreference",
    "ReminderTone" = EXCLUDED."ReminderTone",
    "UpdatedAtUtc" = EXCLUDED."UpdatedAtUtc";

ON CONFLICT ("ClientId", "IngredientId") DO UPDATE
SET "CreatedAtUtc" = EXCLUDED."CreatedAtUtc";

ON CONFLICT ("ClientId", "IngredientId") DO UPDATE
SET
    "Quantity" = EXCLUDED."Quantity",
    "Unit" = EXCLUDED."Unit",
    "UpdatedAtUtc" = EXCLUDED."UpdatedAtUtc";

COMMIT;
